svg.script:
var x1=200,y1=400,x2=400,y2=200,x3=400,y3=400 var v1="",p1="",p2="",p3="",a="",b="",c="",xya="",xyb="",xyc="",v1="",v2="",ut="",ut2="" var click = false var clip_p = new Array([0,0],[0,0],[0,0]) var sol_poly = new Array() function init_eqdegre3(evt) { svgdoc = evt.target.ownerDocument x1 = 200 y1 = 400 x2 = 400 y2 = 400 x3 = 100 y3 = 200 x4 = 500 y4 = 500 ap = svgdoc.getElementById("a") bp = svgdoc.getElementById("b") cp = svgdoc.getElementById("c") dp = svgdoc.getElementById("d") mp = svgdoc.getElementById("m") np = svgdoc.getElementById("n") pp = svgdoc.getElementById("p") p1 = svgdoc.getElementById("p1") p2 = svgdoc.getElementById("p2") p3 = svgdoc.getElementById("p3") p4 = svgdoc.getElementById("p4") p5 = svgdoc.getElementById("p5") p6 = svgdoc.getElementById("p6") p7 = svgdoc.getElementById("p7") u1 = svgdoc.getElementById("u1") v1 = svgdoc.getElementById("v1") w1 = svgdoc.getElementById("w1") z1 = svgdoc.getElementById("z1") cubic = svgdoc.getElementById("cubic") sol1 = svgdoc.getElementById("sol1") sol2 = svgdoc.getElementById("sol2") sol3 = svgdoc.getElementById("sol3") solu = svgdoc.getElementById("solu") eqdegre3_calcul() }
function eqdegre3_move(evt) { if (click) { cible = evt.target.getAttributeNS(null,"id") xm = evt.clientX ym = evt.clientY if (xm < 25 ) xm = 25 if (xm > 675 ) xm = 675 if (ym < 125 ) ym = 125 if (ym > 575 ) ym = 575 if (cible == "p1") { x1 = xm y1 = ym } if (cible == "p2") { x2 = xm y2 = ym } if (cible == "p3") { x3 = xm y3 = ym } if (cible == "p4") { x4 = xm y4 = ym } eqdegre3_calcul() } }
function clip_cubic(a,b,c,d) { max_x = 13 max_y = 9 min_x = -13 min_y = -9 step = 0.1 str = "M" + (350 + 25 * min_x) + "," + (350 - 25 * (a * min_x * min_x * min_x + b * min_x * min_x + c * min_x + d)) + " " for (x = min_x + step; x <= max_x; x += step) str += (350 + 25 * x) + "," + (350 - 25 * (a * x * x * x + b * x * x + c * x + d)) + " " cubic.setAttributeNS(null, "d", str) }
function solve_cubic(a_c,b_c,c_c,d_c) { nb_sol = 0 if ( a_c!= 0 ) { var a_s = 1, b_s = b_c / a_c, c_s = c_c / a_c, d_s = d_c / a_c var a = (3 * c_s - b_s * b_s) / 3 var b = (2 * b_s * b_s * b_s - 9 * c_s * b_s + 27 * d_s) / 27 var offset = b_s / 3 var discrim = b * b / 4 + a * a * a /27 var halfB = b / 2
if ( Math.abs(discrim) <= 0.000001 ) discrim = 0
if ( discrim > 0 ) { var e = Math.sqrt(discrim) var tmp = 0 var root = 0
tmp = -halfB + e if ( tmp >= 0 ) root = Math.pow(tmp, 1/3) else root = -Math.pow(-tmp, 1/3)
tmp = -halfB - e if ( tmp >= 0 ) root += Math.pow(tmp, 1/3) else root -= Math.pow(-tmp, 1/3) root -= offset nb_sol = 1 sol_poly[0] = root } else if ( discrim < 0 ) { var distance = Math.sqrt(-a/3) var angle = Math.atan2( Math.sqrt(-discrim), -halfB) / 3 var cos = Math.cos(angle) var sin = Math.sin(angle) var sqrt3 = Math.sqrt(3)
nb_sol = 3 sol_poly[0] = 2 * distance * cos - offset sol_poly[1] = - distance * (cos + sqrt3 * sin) - offset sol_poly[2] = - distance * (cos - sqrt3 * sin) - offset } else { var tmp = 0
if ( halfB >= 0 ) tmp = -Math.pow(halfB, 1/3) else tmp = Math.pow(-halfB, 1/3)
nb_sol = 3 sol_poly[0] = 2*tmp - offset sol_poly[1] = -tmp - offset sol_poly[2] = -tmp - offset } } }
function eqdegre3_calcul() { p1.setAttributeNS(null,"cx",x1) p1.setAttributeNS(null,"cy",y1) p2.setAttributeNS(null,"cx",x2) p2.setAttributeNS(null,"cy",y2) p3.setAttributeNS(null,"cx",x3) p3.setAttributeNS(null,"cy",y3) p4.setAttributeNS(null,"cx",x4) p4.setAttributeNS(null,"cy",y4) ap.setAttributeNS(null,"x",x1) ap.setAttributeNS(null,"y",y1) bp.setAttributeNS(null,"x",x2) bp.setAttributeNS(null,"y",y2) cp.setAttributeNS(null,"x",x3) cp.setAttributeNS(null,"y",y3) dp.setAttributeNS(null,"x",x4) dp.setAttributeNS(null,"y",y4) xA = parseInt(4 * (x1 - 350)) / 100 yA = parseInt(4 * (350 - y1)) / 100 xB = parseInt(4 * (x2 - 350)) / 100 yB = parseInt(4 * (350 - y2)) / 100 xC = parseInt(4 * (x3 - 350)) / 100 yC = parseInt(4 * (350 - y3)) / 100 xD = parseInt(4 * (x4 - 350)) / 100 yD = parseInt(4 * (350 - y4)) / 100 det = (xA * xA * xA - xB * xB * xB) * (xA * xA - xC * xC) * (xA - xD) det += (xA * xA * xA - xC * xC * xC) * (xA * xA - xD * xD) * (xA - xB) det += (xA * xA * xA - xD * xD * xD) * (xA * xA - xB * xB) * (xA - xC) det -= (xA * xA * xA - xB * xB * xB) * (xA * xA - xD * xD) * (xA - xC) det -= (xA * xA * xA - xC * xC * xC) * (xA * xA - xB * xB) * (xA - xD) det -= (xA * xA * xA - xD * xD * xD) * (xA * xA - xC * xC) * (xA - xB) detx = (yA - yB) * (xA * xA - xC * xC) * (xA - xD) detx += (yA - yC) * (xA * xA - xD * xD) * (xA - xB) detx += (yA - yD) * (xA * xA - xB * xB) * (xA - xC) detx -= (yA - yB) * (xA * xA - xD * xD) * (xA - xC) detx -= (yA - yC) * (xA * xA - xB * xB) * (xA - xD) detx -= (yA - yD) * (xA * xA - xC * xC) * (xA - xB) dety = (xA * xA * xA - xB * xB * xB) * (yA - yC) * (xA - xD) dety += (xA * xA * xA - xC * xC * xC) * (yA - yD) * (xA - xB) dety += (xA * xA * xA - xD * xD * xD) * (yA - yB) * (xA - xC) dety -= (xA * xA * xA - xB * xB * xB) * (yA - yD) * (xA - xC) dety -= (xA * xA * xA - xC * xC * xC) * (yA - yB) * (xA - xD) dety -= (xA * xA * xA - xD * xD * xD) * (yA - yC) * (xA - xB) detz = (xA * xA * xA - xB * xB * xB) * (xA * xA - xC * xC) * (yA - yD) detz += (xA * xA * xA - xC * xC * xC) * (xA * xA - xD * xD) * (yA - yB) detz += (xA * xA * xA - xD * xD * xD) * (xA * xA - xB * xB) * (yA - yC) detz -= (xA * xA * xA - xB * xB * xB) * (xA * xA - xD * xD) * (yA - yC) detz -= (xA * xA * xA - xC * xC * xC) * (xA * xA - xB * xB) * (yA - yD) detz -= (xA * xA * xA - xD * xD * xD) * (xA * xA - xC * xC) * (yA - yB) if ( det != 0 ) { a = detx / det b = dety / det c = detz / det d = yA - a * xA * xA * xA - b * xA * xA - c * xA u1.firstChild.data = Math.round(100 * a) / 100 if (b < 0 ) v1.firstChild.data = Math.round(100 * b) / 100 else v1.firstChild.data = " + " + Math.round(100 * b) / 100 if (c < 0 ) w1.firstChild.data = Math.round(100 * c) / 100 else w1.firstChild.data = " + " + Math.round(100 * c) / 100 if (d < 0 ) z1.firstChild.data = Math.round(100 * d) / 100 else z1.firstChild.data = " + " + Math.round(100 * d) / 100 clip_cubic(a,b,c,d) solve_cubic(a,b,c,d) sol1.firstChild.data = Math.round( 1000 * sol_poly[0]) / 1000 p5.setAttributeNS(null,"cx",350 + 25 * sol_poly[0]) mp.setAttributeNS(null,"x",350 + 25 * sol_poly[0]) if ( nb_sol > 1 ) { sol2.firstChild.data = Math.round( 1000 * sol_poly[1]) / 1000 p6.setAttributeNS(null,"cx",350 + 25 * sol_poly[1]) np.setAttributeNS(null,"x",350 + 25 * sol_poly[1]) sol3.firstChild.data = Math.round( 1000 * sol_poly[2]) / 1000 p7.setAttributeNS(null,"cx",350 + 25 * sol_poly[2]) pp.setAttributeNS(null,"x",350 + 25 * sol_poly[2]) } else { p6.setAttributeNS(null,"cx","-100") np.setAttributeNS(null,"x","-100") p7.setAttributeNS(null,"cx","-100") pp.setAttributeNS(null,"x","-100") } solu.setAttributeNS(null,"visibility","visible") } }
